custom_css:
/* Fix main menu spacing */
.main-nav .menu-item {
    margin-right: 20px !important;
}
.main-nav .menu-item a {
    display: inline-block !important;
    padding: 5px 0 !important;
    transition: all 0.3s !important;
}
.main-nav .menu-item a:hover {
    color: #ff4a5a !important;
}

/* === MOBILE OPTIMIZATION === */
@media (max-width: 768px) {
    /* Ticker: shrink from 120px to 36px */
    .news-ticker-box {
        height: auto !important;
        border-radius: 6px !important;
        margin: 0 -15px !important;
        border-left: none !important;
        border-right: none !important;
    }
    .ticker-label {
        width: 70px !important;
        font-size: 12px !important;
        padding: 8px 5px !important;
    }
    .ticker-wrapper {
        height: 36px !important;
        padding: 0 10px !important;
    }
    .ticker-list li {
        height: 36px !important;
        line-height: 36px !important;
        font-size: 13px !important;
    }
    .ticker-time {
        font-size: 11px !important;
        margin-right: 5px !important;
    }

    /* Carousel: shrink height */
    #homeSlider .carousel-item img {
        height: 180px !important;
        max-height: 25vh !important;
    }
    .carousel-caption {
        display: none !important;
    }

    /* Orange notice bar: compact */
    .orange-notice-bar {
        margin-top: 8px !important;
    }
    .orange-notice-bar > .container > div {
        padding: 8px 12px !important;
        border-radius: 6px !important;
        font-size: 12px !important;
    }

    /* Search: bigger and more prominent */
    .search-section {
        margin-top: 15px !important;
        margin-bottom: 15px !important;
    }
    .search-input-group {
        display: flex !important;
        gap: 0 !important;
        border-radius: 25px !important;
        overflow: hidden !important;
        border: 2px solid #FF5E52 !important;
    }
    .search-input-group .input-wrapper {
        flex: 1 !important;
    }
    .search-input-group .search-field {
        height: 44px !important;
        font-size: 15px !important;
        border: none !important;
        border-radius: 0 !important;
        padding: 0 15px !important;
    }
    .search-input-group .search-icon {
        left: 12px !important;
        font-size: 14px !important;
    }
    .search-input-group .search-submit {
        height: 44px !important;
        padding: 0 20px !important;
        font-size: 15px !important;
        border-radius: 0 !important;
        white-space: nowrap !important;
    }

    /* Ad slot placeholder */
    .yy-main {
        padding-top: 10px !important;
    }
    .ad-slot-mobile-top {
        margin: 0 -15px 15px !important;
        text-align: center !important;
        min-height: 50px !important;
        background: #f8f9fa !important;
        display: flex !important;
        align-items: center !important;
        justify-content: center !important;
    }
    .ad-slot-mobile-bottom {
        margin: 15px -15px 0 !important;
        text-align: center !important;
        min-height: 50px !important;
        background: #f8f9fa !important;
        display: flex !important;
        align-items: center !important;
        justify-content: center !important;
    }

    /* Product cards: cleaner mobile layout */
    .product-list {
        gap: 10px !important;
    }
    .product-list .card {
        border-radius: 8px !important;
        overflow: hidden !important;
    }
    .product-list .card-body {
        padding: 8px !important;
    }
    .product-list .thumbnail img {
        border-radius: 6px !important;
        height: 120px !important;
        object-fit: cover !important;
    }
    .product-list .card-title {
        font-size: 13px !important;
        line-height: 1.4 !important;
        display: -webkit-box !important;
        -webkit-line-clamp: 2 !important;
        -webkit-box-orient: vertical !important;
        overflow: hidden !important;
    }
    .product-list .bottom-data {
        margin-top: 5px !important;
    }
    .product-list .bottom-data .time {
        font-size: 11px !important;
    }
    .product-list .bottom-data .price {
        font-size: 11px !important;
    }

    /* Pagination: compact */
    .pagination {
        margin-top: 20px !important;
    }
    .pagination .page-numbers {
        min-width: 32px !important;
        height: 32px !important;
        line-height: 32px !important;
        font-size: 13px !important;
    }

    /* Section header */
    .section-header h3 {
        font-size: 1.2rem !important;
    }
    .section-header .desc {
        font-size: 12px !important;
    }
    .section-header {
        margin-bottom: 20px !important;
    }
}

/* AdSense desktop ad slots */
.ad-slot-desktop-top {
    text-align: center;
    margin: 15px 0;
    min-height: 90px;
}
.ad-slot-desktop-sidebar {
    text-align: center;
    margin: 15px 0;
    min-height: 250px;
}
.ad-slot-desktop-bottom {
    text-align: center;
    margin: 20px 0;
    min-height: 90px;
}

/* Hide ad slots on wrong device */
.ad-slot-mobile-top, .ad-slot-mobile-bottom {
    display: none;
}
@media (max-width: 768px) {
    .ad-slot-desktop-top, .ad-slot-desktop-sidebar, .ad-slot-desktop-bottom {
        display: none !important;
    }
    .ad-slot-mobile-top, .ad-slot-mobile-bottom {
        display: flex !important;
    }
}
